                emulator.P |= 0x40;
            }

            if (high > 0x90)
            {
                high += 0x60;
            }

            if (high > 0xFF)
            {
                emulator.P |= 0x01;
            }

            emulator.A = (byte)(low & 0b00001111 | high & 0b11110000);
        }
        else
        {
            emulator.A = (byte)binary_result;
            emulator.P &= 0x1C;
            if ((((binary_result ^ left) & (binary_result ^ right) & 0b10000000) != 0x00))
            {
                emulator.P |= 0x40;
            }

            if ((binary_result & 0x0100) != 0x00)
            {
                emulator.P |= 0x01;
            }

            if (emulator.A == 0)
            {
                emulator.P |= 0x02;
            }

            if (((emulator.A & 0b10000000) != 0x00))
